// Validate & repair the AI Agent output so the frontend never crashes on a bad shape.
const LEVELS = ['low', 'medium', 'high'];
const DIM_KEYS = ['concentration', 'diversification', 'volatility', 'liquidity'];

let raw = $input.first().json.output ?? $input.first().json;

// Gemini sometimes wraps JSON in ```json fences — strip them.
if (typeof raw === 'string') {
  raw = raw.trim()
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```$/, '')
    .trim();
  try {
    raw = JSON.parse(raw);
  } catch (e) {
    throw new Error('AI output was not valid JSON: ' + raw.slice(0, 200));
  }
}

const out = raw || {};
const clampLevel = v => LEVELS.includes(v) ? v : 'medium';
const clampScore = v => {
  const n = Number(v);
  return Number.isFinite(n) ? Math.max(0, Math.min(100, Math.round(n))) : 50;
};
const str = (v, fallback = '') => typeof v === 'string' ? v : fallback;

out.overall = out.overall || {};
out.overall.score    = clampScore(out.overall.score);
out.overall.level    = clampLevel(out.overall.level);
out.overall.label    = str(out.overall.label, 'Risk');
out.overall.headline = str(out.overall.headline, '');

out.dimensions = (Array.isArray(out.dimensions) ? out.dimensions : [])
  .filter(d => DIM_KEYS.includes(d?.key))
  .map(d => ({ key: d.key, level: clampLevel(d.level), value: str(d.value) }));

out.assets = (Array.isArray(out.assets) ? out.assets : [])
  .map(a => ({ symbol: str(a?.symbol), level: clampLevel(a?.level), note: str(a?.note) }))
  .filter(a => a.symbol);

out.actions = (Array.isArray(out.actions) ? out.actions : [])
  .filter(s => typeof s === 'string')
  .slice(0, 4);

out.commentary = str(out.commentary);
out.scannedAt  = str(out.scannedAt) || new Date().toISOString();

return [{ json: out }];
